import { useState, useEffect, useMemo, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";
import {
  LayoutDashboard,
  Package,
  ShoppingCart,
  Users,
  BarChart3,
  Settings,
  User,
  LogOut,
  Menu,
  X,
} from "lucide-react";

import { adminDashboardDesign as design } from "../../design/adminDashboardDesign"; // ← adjust path if needed

const menuItems = [
  { name: "Dashboard", icon: LayoutDashboard, active: true },
  { name: "Products",   icon: Package },
  { name: "Orders",     icon: ShoppingCart },
  { name: "Users",      icon: Users },
  { name: "Analytics",  icon: BarChart3 },
  { name: "Settings",   icon: Settings },
];

export default function AdminDashboard() {
  const navigate = useNavigate();
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo") || "{}");

  const [search, setSearch] = useState("");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getInitials = (name = "") => {
    const words = name.trim().split(/\s+/);
    return (words[0]?.[0] ?? "") + (words[1]?.[0] ?? "").toUpperCase();
  };

  const filteredMenu = useMemo(
    () => menuItems.filter((item) =>
      item.name.toLowerCase().includes(search.toLowerCase())
    ),
    [search]
  );

  const handleLogout = () => {
    localStorage.removeItem("adminInfo");
    localStorage.removeItem("token");
    navigate("/admin/login");
  };

  return (
    <div className={design.layout.wrapper}>
      {/* Navbar */}
      <header className={design.layout.navbar}>
        <button
          onClick={() => setSidebarOpen(true)}
          className={design.navbar.menuButton}
          aria-label="Open sidebar"
        >
          <Menu size={24} />
        </button>

        <div className={design.navbar.title}>Admin Panel</div>

        <input
          type="text"
          placeholder="Search menu..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className={design.navbar.search}
        />

        <div className="flex items-center gap-3">
          <button
            ref={dropdownRef}
            onClick={() => setDropdownOpen(!dropdownOpen)}
            className={design.navbar.avatarButton}
          >
            <div className="w-9 h-9 rounded-full bg-gradient-to-br from-indigo-500 to-indigo-700 text-white font-semibold flex items-center justify-center ring-2 ring-white shadow-sm text-sm">
              {getInitials(adminInfo?.name)}
            </div>
            <div className="hidden sm:flex flex-col text-left text-xs">
              <span className="font-medium text-slate-800">
                {adminInfo?.name || "Admin"}
              </span>
              <span className="text-slate-500">
                {adminInfo?.role || "Administrator"}
              </span>
            </div>
          </button>

          <AnimatePresence>
            {dropdownOpen && (
              <motion.div
                initial={{ opacity: 0, y: 8, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, y: 8, scale: 0.95 }}
                className={design.dropdown.wrapper}
              >
                <div className={design.dropdown.header}>
                  <span className="font-medium">{adminInfo?.name}</span>
                  <span className="text-xs text-slate-500 truncate">
                    {adminInfo?.email}
                  </span>
                </div>
                <div
                  onClick={() => navigate("/admin/profile")}
                  className={design.dropdown.item}
                >
                  <User size={16} /> Profile
                </div>
                <div onClick={handleLogout} className={design.dropdown.danger}>
                  <LogOut size={16} /> Logout
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </header>

      {/* Overlay – only on mobile/tablet */}
      <AnimatePresence>
        {sidebarOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setSidebarOpen(false)}
            className={design.colors.overlay}
          />
        )}
      </AnimatePresence>

      {/* Sidebar */}
      <motion.aside
        className={`${design.layout.sidebar} ${
          sidebarOpen ? "translate-x-0" : ""
        } lg:translate-x-0`}
      >
        {/* Mobile/tablet header */}
        <div className={design.sidebar.header}>
          <div className={design.sidebar.brand}>
            <h1 className={design.sidebar.logo}>Admin Panel</h1>
            <span className={design.sidebar.subtitle}>Nahid Enterprise</span>
          </div>
          <button
            onClick={() => setSidebarOpen(false)}
            className={design.sidebar.closeBtn}
            aria-label="Close sidebar"
          >
            <X size={28} />
          </button>
        </div>

        <nav className={design.sidebar.nav}>
          {filteredMenu.map((item) => {
            const Icon = item.icon;
            return (
              <div
                key={item.name}
                className={`
                  ${design.sidebar.navItem}
                  ${item.active ? design.sidebar.navItemActive : ""}
                `}
                onClick={() => {
                  if (window.innerWidth < 1024) setSidebarOpen(false);
                }}
              >
                <Icon size={20} />
                <span>{item.name}</span>
              </div>
            );
          })}
        </nav>
      </motion.aside>

      {/* Main Content */}
      <main className={design.layout.content}>
        <h1 className={design.typography.h1}>
          Welcome back 👋
        </h1>
        <p className={design.typography.subtitle}>
          Here's what's happening with your store today
        </p>

        {/* Your dashboard content goes here */}
      </main>
    </div>
  );
}
